/**
 * API reference directory: drives /api-reference/[endpoint] pages.
 *
 * Each entry is a per-endpoint editorial wrapper around the canonical
 * spec already published in /openapi.json. The pages target branded
 * search queries like "tensorfeed routing api" and give agents
 * searching for a specific capability a direct landing page with
 * code samples in three languages plus the MCP tool name.
 *
 * Endpoints are grouped by category for the index page; per-endpoint
 * pages are auto-generated by the [endpoint] dynamic route.
 */

export type EndpointTier = 'free' | 'free-with-token' | 'premium';
export type EndpointCategory =
  | 'news'
  | 'status'
  | 'models'
  | 'routing'
  | 'history'
  | 'agents'
  | 'watches'
  | 'payment'
  | 'agent-brief'
  | 'security'
  | 'macro'
  | 'climate'
  | 'health'
  | 'policy'
  | 'research';

export interface ApiRefParam {
  name: string;
  in: 'query' | 'path' | 'body';
  required?: boolean;
  type: string;
  description: string;
  example?: string;
}

export interface ApiRefMeta {
  /** URL slug used in /api-reference/[endpoint] */
  slug: string;
  /** Display name */
  name: string;
  /** API path */
  path: string;
  /** HTTP method */
  method: 'GET' | 'POST' | 'DELETE';
  /** Tier */
  tier: EndpointTier;
  /** Cost (credits or "Free") */
  cost: string;
  /** Category for grouping */
  category: EndpointCategory;
  /** SEO title (< 60 chars) */
  seoTitle: string;
  /** SEO description (150-160 chars) */
  seoDescription: string;
  /** One-paragraph intro for the page */
  intro: string;
  /** Why an agent calls this */
  whenToUse: string;
  /** Query / path / body parameters */
  params: ApiRefParam[];
  /** Compact example response (will be JSON-stringified by the page) */
  exampleResponse: string;
  /** Python SDK call (multi-line OK, will be in pre block) */
  pythonExample: string;
  /** TypeScript SDK call */
  typescriptExample: string;
  /** MCP tool name for the same call (or null if not exposed via MCP) */
  mcpTool: string | null;
  /** Related endpoint slugs (link from this page to others) */
  relatedSlugs: string[];
  /** FAQPage entries: question + answer */
  faqs: { q: string; a: string }[];
}

