export function getApiRefBySlug(slug: string): ApiRefMeta | null {
  return API_REFERENCE.find(e => e.slug === slug) ?? null;
}

export function getAllApiRefSlugs(): string[] {
  return API_REFERENCE.map(e => e.slug);
}

export function getApiRefsByCategory(): Record<EndpointCategory, ApiRefMeta[]> {
  const grouped: Partial<Record<EndpointCategory, ApiRefMeta[]>> = {};
  for (const e of API_REFERENCE) {
    if (!grouped[e.category]) grouped[e.category] = [];
    grouped[e.category]!.push(e);
  }
  return grouped as Record<EndpointCategory, ApiRefMeta[]>;
}
